"""sklearn.multioutput — Multi-output classification and regression."""
import numpy as np
from sklearn.base import BaseEstimator, ClassifierMixin, RegressorMixin, clone


class MultiOutputClassifier(BaseEstimator, ClassifierMixin):
    """Multi-output classification: one estimator per output.

    Parameters
    ----------
    estimator : classifier
    """

    def __init__(self, estimator=None):
        self.estimator = estimator

    def fit(self, X, y):
        X = np.asarray(X, dtype=float)
        y = np.asarray(y)
        if y.ndim == 1:
            y = y.reshape(-1, 1)
        self.estimators_ = []
        for j in range(y.shape[1]):
            est = clone(self.estimator)
            est.fit(X, y[:, j])
            self.estimators_.append(est)
        return self

    def predict(self, X):
        X = np.asarray(X, dtype=float)
        return np.column_stack([est.predict(X) for est in self.estimators_])

    def score(self, X, y):
        y = np.asarray(y)
        if y.ndim == 1:
            y = y.reshape(-1, 1)
        preds = self.predict(X)
        return np.mean([np.mean(preds[:, j] == y[:, j]) for j in range(y.shape[1])])


class MultiOutputRegressor(BaseEstimator, RegressorMixin):
    """Multi-output regression: one estimator per output.

    Parameters
    ----------
    estimator : regressor
    """

    def __init__(self, estimator=None):
        self.estimator = estimator

    def fit(self, X, y):
        X = np.asarray(X, dtype=float)
        y = np.asarray(y, dtype=float)
        if y.ndim == 1:
            y = y.reshape(-1, 1)
        self.estimators_ = []
        for j in range(y.shape[1]):
            est = clone(self.estimator)
            est.fit(X, y[:, j])
            self.estimators_.append(est)
        return self

    def predict(self, X):
        X = np.asarray(X, dtype=float)
        return np.column_stack([est.predict(X) for est in self.estimators_])
